36: // Error represents semantic errors on parsing rule groups.
37: type Error struct {
38: 	Group    string
39: 	Rule     int
40: 	RuleName string
41: 	Err      WrappedError
42: }
43: 
44: // Error prints the error message in a formatted string.
45: func (err *Error) Error() string {
46: 	if err.Err.err == nil {
47: 		return ""
48: 	}
49: 	if err.Err.nodeAlt != nil {
50: 		return fmt.Sprintf("%d:%d: %d:%d: group %q, rule %d, %q: %v", err.Err.node.Line, err.Err.node.Column, err.Err.nodeAlt.Line, err.Err.nodeAlt.Column, err.Group, err.Rule, err.RuleName, err.Err.err)
51: 	}
52: 	if err.Err.node != nil {
53: 		return fmt.Sprintf("%d:%d: group %q, rule %d, %q: %v", err.Err.node.Line, err.Err.node.Column, err.Group, err.Rule, err.RuleName, err.Err.err)
54: 	}
55: 	return fmt.Sprintf("group %q, rule %d, %q: %v", err.Group, err.Rule, err.RuleName, err.Err.err)
56: }
57: 
58: // Unwrap unpacks wrapped error for use in errors.Is & errors.As.
59: func (err *Error) Unwrap() error {
60: 	return &err.Err
61: }
62: 
63: // WrappedError wraps error with the yaml node which can be used to represent
64: // the line and column numbers of the error.
65: type WrappedError struct {
66: 	err     error
67: 	node    *yaml.Node
68: 	nodeAlt *yaml.Node
69: }
70: 
71: // Error prints the error message in a formatted string.
72: func (we *WrappedError) Error() string {
73: 	if we.err == nil {
74: 		return ""
75: 	}
76: 	if we.nodeAlt != nil {
77: 		return fmt.Sprintf("%d:%d: %d:%d: %v", we.node.Line, we.node.Column, we.nodeAlt.Line, we.nodeAlt.Column, we.err)
78: 	}
79: 	if we.node != nil {
80: 		return fmt.Sprintf("%d:%d: %v", we.node.Line, we.node.Column, we.err)
81: 	}
82: 	return we.err.Error()
83: }
84: 
85: // Unwrap unpacks wrapped error for use in errors.Is & errors.As.
86: func (we *WrappedError) Unwrap() error {
87: 	return we.err
88: }
