157: // RuleGroup is a list of sequentially evaluated recording and alerting rules.
158: type RuleGroup struct {
159: 	Name        string            `yaml:"name"`
160: 	Interval    model.Duration    `yaml:"interval,omitempty"`
161: 	QueryOffset *model.Duration   `yaml:"query_offset,omitempty"`
162: 	Limit       int               `yaml:"limit,omitempty"`
163: 	Rules       []Rule            `yaml:"rules"`
164: 	Labels      map[string]string `yaml:"labels,omitempty"`
165: }
