200: // Validate the rule and return a list of encountered errors.
201: func (r *Rule) Validate(node RuleNode, nameValidationScheme model.ValidationScheme, p parser.Parser) (nodes []WrappedError) {
202: 	if r.Record != "" && r.Alert != "" {
203: 		nodes = append(nodes, WrappedError{
204: 			err:     errors.New("only one of 'record' and 'alert' must be set"),
205: 			node:    &node.Record,
206: 			nodeAlt: &node.Alert,
207: 		})
208: 	}
209: 	if r.Record == "" && r.Alert == "" {
210: 		nodes = append(nodes, WrappedError{
211: 			err:     errors.New("one of 'record' or 'alert' must be set"),
212: 			node:    &node.Record,
213: 			nodeAlt: &node.Alert,
214: 		})
215: 	}
216: 
217: 	if r.Expr == "" {
218: 		nodes = append(nodes, WrappedError{
219: 			err:  errors.New("field 'expr' must be set in rule"),
220: 			node: &node.Expr,
221: 		})
222: 	} else if _, err := p.ParseExpr(r.Expr); err != nil {
223: 		nodes = append(nodes, WrappedError{
224: 			err:  fmt.Errorf("could not parse expression: %w", err),
225: 			node: &node.Expr,
226: 		})
227: 	}
228: 	if r.Record != "" {
229: 		if len(r.Annotations) > 0 {
230: 			nodes = append(nodes, WrappedError{
231: 				err:  errors.New("invalid field 'annotations' in recording rule"),
232: 				node: &node.Record,
233: 			})
234: 		}
235: 		if r.For != 0 {
236: 			nodes = append(nodes, WrappedError{
237: 				err:  errors.New("invalid field 'for' in recording rule"),
238: 				node: &node.Record,
239: 			})
240: 		}
241: 		if r.KeepFiringFor != 0 {
242: 			nodes = append(nodes, WrappedError{
243: 				err:  errors.New("invalid field 'keep_firing_for' in recording rule"),
244: 				node: &node.Record,
245: 			})
246: 		}
247: 		if !nameValidationScheme.IsValidMetricName(r.Record) {
248: 			nodes = append(nodes, WrappedError{
249: 				err:  fmt.Errorf("invalid recording rule name: %s", r.Record),
250: 				node: &node.Record,
251: 			})
252: 		}
253: 		// While record is a valid UTF-8 it's common mistake to put PromQL expression in the record name.
254: 		// Disallow "{}" chars.
255: 		if strings.Contains(r.Record, "{") || strings.Contains(r.Record, "}") {
256: 			nodes = append(nodes, WrappedError{
257: 				err:  fmt.Errorf("braces present in the recording rule name; should it be in expr?: %s", r.Record),
258: 				node: &node.Record,
259: 			})
260: 		}
261: 	}
262: 
263: 	for k, v := range r.Labels {
264: 		if !nameValidationScheme.IsValidLabelName(k) || k == model.MetricNameLabel {
265: 			nodes = append(nodes, WrappedError{
266: 				err: fmt.Errorf("invalid label name: %s", k),
267: 			})
268: 		}
269: 
270: 		if !model.LabelValue(v).IsValid() {
271: 			nodes = append(nodes, WrappedError{
272: 				err: fmt.Errorf("invalid label value: %s", v),
273: 			})
274: 		}
275: 	}
276: 
277: 	for k := range r.Annotations {
278: 		if !nameValidationScheme.IsValidLabelName(k) {
279: 			nodes = append(nodes, WrappedError{
280: 				err: fmt.Errorf("invalid annotation name: %s", k),
281: 			})
282: 		}
283: 	}
284: 
285: 	for _, err := range testTemplateParsing(r) {
286: 		nodes = append(nodes, WrappedError{err: err})
287: 	}
288: 
289: 	return nodes
290: }
