292: // testTemplateParsing checks if the templates used in labels and annotations
293: // of the alerting rules are parsed correctly.
294: func testTemplateParsing(rl *Rule) (errs []error) {
295: 	if rl.Alert == "" {
296: 		// Not an alerting rule.
297: 		return errs
298: 	}
299: 
300: 	// Trying to parse templates.
301: 	tmplData := template.AlertTemplateData(map[string]string{}, map[string]string{}, "", promql.Sample{})
302: 	defs := []string{
303: 		"{{$labels := .Labels}}",
304: 		"{{$externalLabels := .ExternalLabels}}",
305: 		"{{$externalURL := .ExternalURL}}",
306: 		"{{$value := .Value}}",
307: 	}
308: 	parseTest := func(text string) error {
309: 		tmpl := template.NewTemplateExpander(
310: 			context.TODO(),
311: 			strings.Join(append(defs, text), ""),
312: 			"__alert_"+rl.Alert,
313: 			tmplData,
314: 			model.Time(timestamp.FromTime(time.Now())),
315: 			nil,
316: 			nil,
317: 			nil,
318: 		)
319: 		return tmpl.ParseTest()
320: 	}
321: 
322: 	// Parsing Labels.
323: 	for k, val := range rl.Labels {
324: 		err := parseTest(val)
325: 		if err != nil {
326: 			errs = append(errs, fmt.Errorf("label %q: %w", k, err))
327: 		}
328: 	}
329: 
330: 	// Parsing Annotations.
331: 	for k, val := range rl.Annotations {
332: 		err := parseTest(val)
333: 		if err != nil {
334: 			errs = append(errs, fmt.Errorf("annotation %q: %w", k, err))
335: 		}
336: 	}
337: 
338: 	return errs
339: }
