341: // Parse parses and validates a set of rules.
342: func Parse(content []byte, ignoreUnknownFields bool, nameValidationScheme model.ValidationScheme, p parser.Parser) (*RuleGroups, []error) {
343: 	var (
344: 		groups RuleGroups
345: 		node   ruleGroups
346: 		errs   []error
347: 	)
348: 
349: 	decoder := yaml.NewDecoder(bytes.NewReader(content))
350: 	if !ignoreUnknownFields {
351: 		decoder.KnownFields(true)
352: 	}
353: 	err := decoder.Decode(&groups)
354: 	// Ignore io.EOF which happens with empty input.
355: 	if err != nil && !errors.Is(err, io.EOF) {
356: 		errs = append(errs, err)
357: 	}
358: 	err = yaml.Unmarshal(content, &node)
359: 	if err != nil {
360: 		errs = append(errs, err)
361: 	}
362: 
363: 	if len(errs) > 0 {
364: 		return nil, errs
365: 	}
366: 
367: 	return &groups, groups.Validate(node, nameValidationScheme, p)
368: }
