370: // ParseFile reads and parses rules from a file.
371: func ParseFile(file string, ignoreUnknownFields bool, nameValidationScheme model.ValidationScheme, p parser.Parser) (*RuleGroups, []error) {
372: 	b, err := os.ReadFile(file)
373: 	if err != nil {
374: 		return nil, []error{fmt.Errorf("%s: %w", file, err)}
375: 	}
376: 	rgs, errs := Parse(b, ignoreUnknownFields, nameValidationScheme, p)
377: 	for i := range errs {
378: 		errs[i] = fmt.Errorf("%s: %w", file, errs[i])
379: 	}
380: 	return rgs, errs
381: }
